    $release = $family->payoutReleases->first();
    $requirement = $family->postPayoutRequirement;
    $memberComposition = $family->familyMembers->map(fn ($member) => ['name'=>$member->name,'birthdate'=>$member->birthdate?->format('Y-m-d'),'age'=>$member->age,'relationship'=>$member->relationship_to_head,'sex'=>$member->sex,'occupation'=>$member->occupation,'health'=>$member->health_condition,'remarks'=>$member->remarks_codes])->values();
    return [$family->id => ['reference'=>$family->dafacRecord?->reference_number,'surname'=>$family->household_head_surname,'given_name'=>$family->household_head_given_name,'middle_name'=>$family->household_head_middle_name,'household'=>$family->household_head_full_name,'birthdate'=>$family->birthdate?->format('Y-m-d'),'age'=>$family->age,'occupation'=>$family->occupation,'monthly_income'=>$family->monthly_income,'contact'=>$family->contact_number,'address'=>$family->complete_address,'barangay'=>$family->barangay?->name,'center'=>$release?->center?->name??$family->evacuationCenter?->name,'members'=>$family->familyMembers->count()+1,'member_composition'=>$memberComposition,'ownership'=>$family->house_ownership,'housing'=>$family->housing_condition,'health'=>$family->health_condition,'status'=>'Paid','assistance'=>$release?->assistance_kind,'quantity'=>$release?->quantity,'amount'=>$release?->amount,'provider'=>$release?->provider,'released_at'=>$release?->released_at?->format('M d, Y h:i A'),'released_by'=>$release?->releaser?->name,'caption'=>$release?->photo_caption,'photo'=>$release?->payout_photo_path?route('disaster.payroll.photo',$release):null,'requirements_url'=>route('disaster.payroll.requirements',$family),'bfp_status'=>$requirement?->bfp_certificate_status??'Pending','barangay_status'=>$requirement?->barangay_certification_status??'Pending','bfp_name'=>$requirement?->documents->where('document_type','bfp_document')->sortByDesc('id')->first()?->original_name,'barangay_name'=>$requirement?->documents->where('document_type','barangay_document')->sortByDesc('id')->first()?->original_name]];
});
