@push('scripts')<script>
(()=>{const records=@json($payrollModalRecords);const modal=new bootstrap.Modal('#releaseDetailsModal'),esc=v=>String(v??'—').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c])),grid=data=>Object.entries(data).map(([label,value])=>`<div class="detail-item"><div class="detail-label">${esc(label)}</div><div class="detail-value">${esc(value)}</div></div>`).join('');document.querySelectorAll('.open-release').forEach(button=>button.onclick=()=>{const r=records[button.dataset.familyId];document.querySelector('#release-household-title').textContent=r.household;document.querySelector('#release-reference').textContent=r.reference||'No DAFAC reference';document.querySelector('#household-details').innerHTML=grid({'Surname':r.surname,'Given Name':r.given_name,'Middle Name':r.middle_name,'Birthdate / Age':`${r.birthdate||'—'} / ${r.age??'—'}`,'Occupation':r.occupation,'Monthly Income':r.monthly_income,'Contact Number':r.contact,'Complete Address':r.address,'Barangay':r.barangay,'Evacuation Center':r.center,'House Ownership':r.ownership,'Housing Condition':r.housing,'Health Condition':r.health,'Household Size':r.members,'Status':r.status});document.querySelector('#payroll-family-members').innerHTML=r.member_composition.length?r.member_composition.map(member=>`<tr><td class="fw-semibold">${esc(member.name)}</td><td>${esc(member.birthdate)} / ${esc(member.age)}</td><td>${esc(member.relationship)}</td><td>${esc(member.sex)}</td><td>${esc(member.occupation)}</td><td>${esc(member.health)}</td><td>${esc(member.remarks)}</td></tr>`).join(''):'<tr><td colspan="7" class="text-center text-muted py-8">No additional family members recorded.</td></tr>';document.querySelector('#payout-details').innerHTML=grid({'Assistance Type':r.assistance,'Quantity':r.quantity,'Amount':`₱${Number(r.amount||0).toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}`,'Provider':r.provider,'Released On':r.released_at,'Released By':r.released_by,'Status':r.status});const image=document.querySelector('#release-photo'),empty=document.querySelector('#no-release-photo');if(r.photo){image.src=r.photo;image.classList.remove('d-none');empty.classList.add('d-none')}else{image.removeAttribute('src');image.classList.add('d-none');empty.classList.remove('d-none')}document.querySelector('#photo-caption').textContent=r.caption||'';modal.show()})})();
(()=>{const records=@json($payrollModalRecords),csrf=document.querySelector('meta[name=csrf-token]').content;let active;const badge=(element,status)=>{element.textContent=status;element.className=`badge badge-light-${status==='Verified'?'success':status==='Submitted'?'primary':'warning'}`},populate=r=>{active=r;badge(document.querySelector('#bfp-status'),r.bfp_status);badge(document.querySelector('#barangay-status'),r.barangay_status);document.querySelector('#bfp-file-name').textContent=r.bfp_name||'No document uploaded.';document.querySelector('#barangay-file-name').textContent=r.barangay_name||'No document uploaded.';document.querySelector('#requirements-form').reset();document.querySelector('#requirements-alert').classList.add('d-none');bootstrap.Tab.getOrCreateInstance(document.querySelector('#household-tab')).show()};document.querySelectorAll('.open-release').forEach(button=>button.addEventListener('click',()=>populate(records[button.dataset.familyId])));document.querySelector('#requirements-form').addEventListener('submit',async event=>{event.preventDefault();if(!active)return;const button=document.querySelector('#save-requirements'),alertBox=document.querySelector('#requirements-alert'),fd=new FormData(event.target);button.disabled=true;alertBox.classList.add('d-none');try{const response=await fetch(active.requirements_url,{method:'POST',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf},body:fd}),payload=await response.json().catch(()=>({}));if(!response.ok)throw new Error(payload.message||Object.values(payload.errors||{}).flat().join('\n')||'Requirements could not be uploaded.');Object.assign(active,payload.data);populate(active);bootstrap.Tab.getOrCreateInstance(document.querySelector('#requirements-tab')).show();alertBox.textContent=payload.message;alertBox.className='alert alert-success'}catch(error){alertBox.textContent=error.message;alertBox.className='alert alert-danger'}finally{button.disabled=false}})})();
</script>@endpush
